(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["chunk-20357d28"],{"1d7d":function(n,e,t){},3840:function(n,e,t){"use strict";t("1d7d")},a11a:function(n,e,t){"use strict";t.r(e);var i=function(){var n=this,e=n.$createElement,t=n._self._c||e;return t("view-box",{ref:"viewBox",staticClass:"privacy",attrs:{"body-padding-bottom":0}},[t("h2",{staticStyle:{"text-align":"center"}},[n._v("智服云用户隐私保护政策")]),t("pre",{staticStyle:{"white-space":"pre-line"}},[n._v("\n    厦门市比牛信息科技有限公司（以下简称“我们”或“比牛科技”）尊重并保护用户隐私，在您使用智服云（以下简称“产品”或“应用”）提供的服务时，我们将按照《智服云用户隐私保护政策》（以下简称“本隐私政策”）收集、使用及共享您的个人信息。\n    本隐私政策包含了我们收集、存储、使用、共享和保护您的个人信息的条款，我们希望通过本隐私政策向您清晰地介绍我们对您个人信息的处理方式，因此我们建议您完整地阅读本隐私政策，以帮助您了解维护自己隐私权的方式。\n    如果您不同意本隐私政策任何内容，您应立即停止使用产品。当您使用产品提供的任一服务时，即表示您已同意我们按照本隐私政策来合法使用和保护您的个人信息。\n\n    "),t("b",[n._v("一、 适用范围")]),n._v("\n    本隐私政策适用于比牛科技提供的所有服务，您访问比牛科技网站、客户端及未设独立隐私政策的关联公司网站、或登陆相关客户端使用比牛科技提供的服务，均适用本隐私政策。\n    需要特别说明的是，本隐私政策不适用于其他第三方向您提供的服务。\n\n    "),t("b",[n._v("二、 我们收集哪些个人信息")]),n._v("\n    为了向您提供更好、更优的服务，我们将根据您使用的服务收集您的如下信息：\n    (1) 您向我们提供的信息。您在注册账户时，向我们提供的相关个人信息，例如电话号码、姓名、电子邮件等；我们还会记录您在使用我们服务时提供的信息，例如您在产品上发布的信息及比牛科技客服联系时您提供的相关信息。\n    (2) 在您使用服务过程中产生的信息。我们会根据您授予的权限，接收并记录您所使用的设备相关信息，这些设备信息包括：设备属性信息（如设备型号、操作系统版本、设备设置、唯一设备标识符等软硬件特征信息）、设备位置信息（如通过GPS、蓝牙或WIFI信号获得的位置信息）、设备连接信息（IP地址、电信运营商、使用的语言、访问日期和时间等）。\n    (3) 来自第三方的信息。当您与使用我们服务的关联公司、比牛科技合作伙伴之间互动时，为共同向您提供服务及改进服务质量的合理需要，我们将从关联公司、合作伙伴处接收关于您的体验或您与其互动的信息。\n\n    "),t("b",[n._v("三、 我们可能如何收集信息 ")]),n._v("\n    我们或我们的第三方合作伙伴，可能通过cookies和web beacon收集和使用您的信息，并将该等信息储存为日志信息。 我们使用自己的cookies和web beacon，目的是为您提供更好的用户体验和服务，并用于以下用途： (1) 记住您的身份。例如：cookies和web beacon有助于我们辨认您作为我们的注册用户的身份。 (2)分析您使用我们服务的情况。例如，我们可利用cookies和web beacon来了解您使用我们的服务进行什么活动，或哪些服务最受您的欢迎。\n\n    "),t("b",[n._v("四、 我们如何使用收集到的信息")]),n._v("\n    收集您的信息是为了向您提供服务及提升服务质量，为了实现这一目的，我们会把您的信息用于下列用途： (1)向您提供您使用的各项服务，并维护、改进这些服务。(2)我们可能使用您的个人信息以预防、发现、调查欺诈、危害安全、非法或违反与我们或其关联方协议、政策或规则的行为，以保护您、我们的其他用户、我们或我们关联方的合法权益。(3) 我们可能会将来自某项服务的信息与来自其他服务的信息结合起来，以便为您提供服务、和建议。 (4) 经您许可的其他用途。 但无论如何，我们仅在本隐私政策所述目的所必需的期间和法律法规要求的时限内保留您的个人信息。\n\n    "),t("b",[n._v("五、 我们可能分享的信息 除以下情形外，未经您同意，我们以及我们的关联公司不会与任何第三方分享您的个人信息：")]),n._v("\n    我们以及我们的关联公司，可能将您的个人信息与我们的关联公司、合作伙伴及第三方服务供应商、承包商及代理（例如代表我们发出电子邮件或推送通知的通讯服务提供商、为我们提供位置数据的地图服务供应商）分享（他们可能并非位于您所在的法域），用作下列用途：\n    (1) 向您提供我们的服务； (2) 实现“我们如何使用收集到的信息”部分所述目的； (3)\n    履行我们在本隐私政策或比牛科技其他产品的用户协议中的义务和行使我们的权利； (4) 理解、维护和改善我们的服务。\n    如我们或我们的关联公司与任何上述第三方分享您的个人信息，我们将努力确保该等第三方在使用您的个人信息时遵守本隐私政策及我们要求其遵守的其他适当的保密和安全措施。\n    随着我们业务的持续发展，我们以及我们的关联公司有可能进行合并、收购、资产转让或类似的交易，您的个人信息有可能作为此类交易的一部分而被转移。我们将在转移前通知您。\n    我们或我们的关联公司还可能为以下需要而保留、保存或披露您的个人信息： (1) 遵守适用的法律法规； (2)\n    遵守法院命令或其他法律程序的规定； (3) 遵守相关政府机关的要求； (4)\n    为遵守适用的法律法规、维护社会公共利益，或保护我们的客户、我们或我们的集团公司、其他用户或雇员的人身和财产安全或合法权益所合理必需的用途。\n\n    "),t("b",[n._v("六、 您如何管理自己的信息")]),n._v("\n    我们提供了便捷的方法，让您可以查询、更正及删除自己的账户信息等使用我们服务时您提供的个人信息。如果您认为我们存在违反法律、行政法规的规定或者与您的约定收集、使用您个人信息的，您可以拨打400-622-6526与我们取得联系。\n\n    "),t("b",[n._v("七、 您的个人信息保护")]),n._v("\n    我们非常重视您的个人信息安全。我们努力采取各种合理的物理、电子和管理方面的安全措施来保护您的个人信息，并尽最大合理努力使您的个人信息不会被泄漏、毁损或者丢失，包括但不限于SSL、信息加密存储、数据中心的访问控制。我们对可能接触到您个人信息的员工或外包人员也采取了严格管理，包括但不限于采取信息访问权限控制、与接触个人信息的人员签署保密协议、监控该等人员的操作情况等措施。\n    您的账户信息（包括网站及客户端账号名、密码信息）为非常重要的个人信息，请您妥善设置、保管您的账号名及密码信息。我们将通过备份、对密码进行加密等安全措施以保护您的账户信息等个人信息不丢失、不被滥用和变造。尽管有前述安全措施，但同时也请您理解在信息网络上不存在“完善的安全措施”。\n    请注意，单独的设备信息等是无法与任何特定个人直接建立联系的数据，不属于个人信息。如果我们将这类非个人信息与其他信息结合用于识别自然人个人身份，或者将其与个人信息结合使用，则在结合使用期间，此类设备信息将被视为个人信息。\n\n    "),t("b",[n._v("八、 未成年人保护")]),n._v("\n    我们重视未成年人的个人信息保护，如您为未成年人，建议您请您的监护人仔细阅读本隐私政策，并在征得您的监护人同意的前提下使用我们的服务或向我们提供信息。\n\n    "),t("b",[n._v("九、 商业信息 我们可能使用您的相关信息，向您提供与您更加相关的商业信息。")]),n._v("\n    我们也可能使用您的信息，通过我们的服务、电子邮件或其他方式向您发送商业信息，提供或推广我们或第三方的商品或服务。\n    如您不希望我们将您的个人信息用作前述商业用途，您可以拨打400-622-6526与我们取得联系。\n\n    "),t("b",[n._v("十、我们可能向您发送的邮件和信息")]),n._v("\n    邮件和信息推送。您在使用我们的服务时，我们可能使用您的信息向您的设备发送电子邮件或推送通知。我们可能在必要时（例如因系统维护而暂停某一项服务时）向您发出与服务有关的公告。您可能无法取消这些与服务有关、性质不属于推广的公告。\n\n    "),t("b",[n._v("十一、需要您授权的功能 ")]),n._v("\n    为实现产品和服务相关功能，我们可能需要您授权我们使用您终端设备中的相关权限，包括但不限于：\n    麦克风权限，以便在录制语音等功能中采集您的声音； 相机权限，以便在拍照上传头像、工单进度等功能中采集所需图像；\n    相册权限，以便在上传头像、工单进度等功能中采集相关图片；\n    位置权限，以便管理员或派单员等查看您所在位置，并根据您所在的位置向您指派工单等的功能。\n\n    "),t("b",[n._v("十二、其中应用集成了极光推送SDK，来为应用提供推送功能。")]),n._v("\n    ①需要收集设备信息（IMEI/MAC/Android ID/IDFA/OAID/UAID/OpenUDID/GUID/SIM卡IMSI信息等）：用于识别唯一用户，保证消息分享的精准送达；网络信息与位置信息（IP地址，WiFi信息，基站信息等相关信息）。\n    ②网络信息与 位置信息 （详见“附录1：关键词定义”） ：用于优化SDK与极光服务器的网络连接请求，保证服务的稳定性和连续性；同时实现区域推送功能；\n    ③APP应用列表及活跃状态信息：当极光推送SDK被不同开发者集成到不同的App后，我们采用合并链路技术进行技术推送，当一个设备有多个APP的推送链路同时活跃时，我们会随机合并成一条链路，以达到为用户节省电省流量的目的；\n    极光隐私权政策链接："),t("a",{attrs:{target:"_blank",href:"https://www.jiguang.cn/license/privacy"}},[n._v("《AURORA极光隐私政策》")]),n._v("\n\n    为向您提供工单定位功能/服务，我们集成了百度定位SDK。在为您提供定位功能/服务时，百度定位SDK需要收集、使用您必要的个人信息，包括设备信息（Android ID、IDFA、操作系统版本、设备品牌及型号、设备配置、应用信息（应用名）），位置信息（可能包括GNSS信息、WiFi地址及信号强度信息、基站ID数据信息、运营商信息、传感器信息、设备信号强度信息、IP地址和蓝牙信息），连接WiFi信息（包括WiFi状态、WiFi参数和WiFi列表）。为了保证最终用户能正常使用百度定位SDK相应功能及服务，我们会通过开发者应用向系统申请最终用户设备的以下系统设备权限，申请前我们会征询最终用户的同意，最终用户可以选择“允许”或“禁止”权限申请。关于【百度定位SDK收集、使用的个人信息类型、目的及用途，以及百度定位SDK将如何保护所收集、使用的个人信息，请您仔细阅读"),t("a",{attrs:{target:"_blank",href:"http://lbsyun.baidu.com/index.php?title=open/privacy"}},[n._v("《百度地图开放平台产品和服务隐私政策》")]),n._v("了解。\n\n    "),t("b",[n._v("十三、注销你的账号")]),n._v("\n\n    你可以在APP个人信息页面的[注销账号]按钮申请注销账号。在你注销账号前，我们将验证你的个人身份、安全状态、设备信息等。你知悉并理解，注销账号的行为是不可逆的行为，当你注销账号后，我们将删除有关你的相关信息或进行匿名化处理，但法律法规另有规定的除外，同时您也无法通过已注销的账户获得我们产品的服务。\n\n    "),t("b",[n._v("十四、本政策的修订 ")]),n._v("\n    我们可不定期修改本隐私政策，变更后的隐私政策将在修订生效前通过比牛科技平台公告或以其他适当方式通知您。该等情况下，若您继续使用我们的服务，即表示同意受经修订的隐私政策的约束。\n\n\n    "),t("b",[n._v("十五、联系我们")]),n._v("\n    如果您对个人信息保护问题有投诉、建议、疑问，或者对本隐私政策有任何疑问、意见或建议您可以将问题发送至（"),t("a",{attrs:{href:"mailto:zdg@zhongyifu.cn"}},[n._v("zdg@zhongyifu.cn")]),n._v("），或者通过"),t("a",{attrs:{href:"tel:13489145937"}},[n._v("13489145937")]),n._v("与我们联系，我们核查并验证您的用户身份后会及时反馈您的投诉与举报\n")])])},v=[],a=t("2ae3"),_={name:"privacy",components:{ViewBox:a["a"]},data:function(){return{}},created:function(){}},c=_,o=(t("3840"),t("2877")),b=Object(o["a"])(c,i,v,!1,null,null,null);e["default"]=b.exports}}]);